// Types
export interface Expense {
  id?: string;
  amount: number;
  category: string;
  vendor: string;
  date: string;
  rawText: string;
  createdAt: Date | string;
}

const STORAGE_KEY = "@ai_expenses_data";

// Helper functions using LocalStorage instead of Firebase
export const addExpense = async (expense: Omit<Expense, "id" | "createdAt">) => {
  try {
    const expenses = await getExpenses();
    const newExpense: Expense = {
      ...expense,
      id: Math.random().toString(36).substring(2, 11),
      createdAt: new Date().toISOString(),
    };
    
    // Simulate network delay to feel realistic
    await new Promise(resolve => setTimeout(resolve, 300));
    
    const updated = [newExpense, ...expenses];
    if (typeof window !== "undefined") {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(updated));
    }
    
    return newExpense;
  } catch (e) {
    console.error("Error adding document to local storage: ", e);
    throw e;
  }
};

export const getExpenses = async (): Promise<Expense[]> => {
  try {
    if (typeof window !== "undefined") {
      const data = localStorage.getItem(STORAGE_KEY);
      if (data) {
        return JSON.parse(data) as Expense[];
      }
    }
    return [];
  } catch (e) {
    console.error("Error fetching generic document from local storage: ", e);
    return [];
  }
};
