"use client";

import { useEffect, useState } from "react";
import { VoiceInput } from "@/components/VoiceInput";
import { Dashboard } from "@/components/Dashboard";
import { Insights } from "@/components/Insights";
import { addExpense, getExpenses, Expense } from "@/lib/firebase";

export default function Home() {
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isProcessingVoice, setIsProcessingVoice] = useState(false);

  useEffect(() => {
    const fetchInitialLogs = async () => {
      try {
        const data = await getExpenses();
        setExpenses(data);
      } catch (error) {
        console.error("Error fetching initial expenses:", error);
      } finally {
        setIsLoading(false);
      }
    };
    fetchInitialLogs();
  }, []);

  const handleTranscript = async (transcript: string) => {
    setIsProcessingVoice(true);
    try {
      // 1. Send text to our AI Parse API
      const res = await fetch("/api/parse-expense", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ transcript }),
      });

      if (!res.ok) {
        const errData = await res.json().catch(() => ({}));
        throw new Error(errData.error || "Failed connecting to AI API");
      }
      
      const parsedData = await res.json();
      
      // 2. Validate parsed data & Structure for DB
      if (parsedData && parsedData.amount) {
         const newExpenseData = {
           amount: Number(parsedData.amount),
           category: parsedData.category || "Uncategorized",
           vendor: parsedData.vendor || "Unknown",
           date: parsedData.date || new Date().toISOString().split('T')[0],
           rawText: transcript
         };

         // 3. Save to Firebase DB
         const savedExpense = await addExpense(newExpenseData);
         
         // 4. Update UI State
         setExpenses(prev => [savedExpense as Expense, ...prev]);
      } else {
        alert("Couldn't understand the expense completely. Please try again.");
      }

    } catch (error: any) {
      console.error("Pipeline error:", error);
      alert("Error: " + (error.message || "An error occurred while processing your expense."));
    } finally {
      setIsProcessingVoice(false);
    }
  };

  return (
    <main className="min-h-screen relative p-6 sm:p-12 overflow-x-hidden selection:bg-primary-500/30">
      {/* Decorative blobs for modern UI */}
      <div className="absolute top-0 left-0 w-[500px] h-[500px] bg-primary-600/20 rounded-full blur-[100px] -translate-x-1/2 -translate-y-1/2" />
      <div className="absolute top-1/2 right-0 w-[400px] h-[400px] bg-blue-500/20 rounded-full blur-[100px] translate-x-1/3" />
      
      <div className="max-w-5xl mx-auto space-y-10 relative z-10">
        
        <header className="text-center space-y-4 pt-10 pb-6 animate-in fade-in slide-in-from-top-6 duration-700">
          <h1 className="text-4xl md:text-5xl font-extrabold tracking-tight bg-gradient-to-br from-foreground to-foreground/70 bg-clip-text text-transparent">
            AI Expense Tracker
          </h1>
          <p className="text-foreground/60 max-w-xl mx-auto">
            Just say what you spent. We'll extract the details, log the date, and analyze your finances.
          </p>
        </header>
        
        <section className="animate-in zoom-in-95 duration-500 delay-100">
          <VoiceInput onTranscriptComplete={handleTranscript} isProcessing={isProcessingVoice} />
        </section>

        <section className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-6">
            <h2 className="text-2xl font-bold mb-4 px-2">Your Dashboard</h2>
            {isLoading ? (
              <div className="glass dark:glass-dark rounded-3xl p-12 text-center animate-pulse-slow">
                Loading your data...
              </div>
            ) : (
              <Dashboard expenses={expenses} />
            )}
          </div>
          <div className="space-y-6">
             <h2 className="text-2xl font-bold mb-4 px-2">Insights</h2>
             <Insights expenses={expenses} />
          </div>
        </section>

      </div>
    </main>
  );
}
